playsCMS = nflgame.combine_max_stats(games)
Player = "M.Jones"

for play in playsCMS:
	if play.name == Player:
		print "Combine Plays:", play.name, "Fumble Total:", play.fumbles_tot
	
for playCP in playsCP:
    for player in playCP.players.filter(fumbles_tot__ge=1):
		if player.name == Player:
			print "Combine Max Stat:", playCP

